const json = $input.item.json;
const f = json.Felder || json.fields || {};

// SharePoint Daten extrahieren
const thema   = f.Field_1 || f.field_1 || '(kein Thema)';
const itemId  = parseInt(String(json.AUSWEIS || json.id || 0).trim(), 10);

// System-Prompt für Claude mit Canva MCP
const systemPrompt = `Du bist ein Automatisierungsassistent für Physio Fuchs Social Media Grafiken.

Führe diese Schritte VOLLSTÄNDIG und NACHEINANDER aus:
1. Starte eine Editing-Session für Canva Design ID: DAG_tS-3P0k
2. Ersetze auf Seite 3 (page_index 3) den Text "THEMA" durch den Thema-Text aus der Benutzernachricht (element_id: PB3DLldpqyKKJNBj-LBRqHYLk6GzfMW2G)
3. Committe die Änderung
4. Exportiere das Design als PNG (nur Seite 3)
5. Warte bis der Export-Link verfügbar ist
6. Antworte AUSSCHLIESSLICH mit diesem JSON (kein Markdown, keine Erklärung):
{"export_url":"URL_ZUM_EXPORT","design_id":"DAG_tS-3P0k","thema":"THEMA_TEXT","status":"success"}`;

// User-Nachricht
const userMessage = `Thema: ${thema}\nSharePoint-Item-ID: ${itemId}\n\nBitte ersetze THEMA mit "${thema}" und exportiere Seite 3 als PNG.`;

return {
  json: {
    // Claude API Payload mit Canva MCP
    model: 'claude-sonnet-4-20250514',
    max_tokens: 4000,
    system: systemPrompt,
    messages: [{ role: 'user', content: userMessage }],
    mcp_servers: [
      {
        type: 'url',
        url: 'https://mcp.canva.com/mcp',
        name: 'canva'
      }
    ],
    // Metadaten für spätere Nodes
    _meta: {
      sharepoint_item_id: itemId,
      thema: thema
    }
  }
};

const response = $input.item.json;
const prev = $('Build Canva Payload').item.json._meta;

// Claude Antwort auswerten
const content = response.content || [];
let exportUrl = '';
let status = 'failed';
let thema = prev?.thema || '';

for (const block of content) {
  if (block.type === 'text' && block.text) {
    const text = block.text.trim();
    // JSON extrahieren
    try {
      const cleaned = text.replace(/```json\n?/gi,'').replace(/```\n?/g,'').trim();
      const parsed = JSON.parse(cleaned);
      exportUrl = parsed.export_url || '';
      status = parsed.status || 'failed';
      thema = parsed.thema || thema;
      break;
    } catch(e) {
      // URL direkt aus Text extrahieren
      const urlMatch = text.match(/https?:\/\/[^\s"']+/g);
      if (urlMatch) {
        // Canva Export URLs bevorzugen
        const canvaUrl = urlMatch.find(u => u.includes('canva') || u.includes('export'));
        exportUrl = canvaUrl || urlMatch[0];
        status = 'success';
      }
    }
  }
}

if (!exportUrl) {
  throw new Error('Kein Export-URL in Claude Antwort gefunden. Response: ' + JSON.stringify(response).substring(0, 500));
}

return {
  json: {
    export_url: exportUrl,
    design_id: 'DAG_tS-3P0k',
    thema: thema,
    status: status,
    sharepoint_item_id: prev?.sharepoint_item_id || 0,
    generated_at: new Date().toISOString()
  }
};
